import{_ as i,o as a,c,ag as s}from"./chunks/framework.CAXxHpAX.js";const x=JSON.parse('{"title":"第二次工业革命   19C","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-44.md","filePath":"notes/note-44.md"}'),v={name:"notes/note-44.md"};function l(r,d,e,o,t,n){return a(),c("div",null,[...d[0]||(d[0]=[s('<h1 id="第二次工业革命-19c" tabindex="-1">第二次工业革命 19C <a class="header-anchor" href="#第二次工业革命-19c" aria-label="Permalink to &quot;第二次工业革命   19C&quot;">​</a></h1><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>第二次工业革命 19C</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>6</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>0、70S-20C初</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">特点：</span>科学研究与工业生产紧密结合；在主要资本主义国家同时展开（以美德为主）；有的国家两次工业革命交替进行；以重工业为主。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>①改善了人们的生活，促进了生产力的发展，人类进入“电气时代”。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>②使主要资本主义国家取得了 跨越式发展，成为工业化强国。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>③主要资本主义国家出现了垄断组织，资本主义由自由资本主义向垄断资本主义即帝国主义阶段过渡。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>④资本主义对外扩张増强，掀起瓜分世界的狂潮。资本主义世界市场最终形成。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">⑤消极：</span>环境污染、贫富分化、扩大战争带来的灾难。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>英国 法拉第——电磁感应现象 美国 爱迪生——电灯</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>德国 奥托——煤气内燃机 戴姆勒——汽油内燃机 狄塞尔——柴油内燃机</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>德国 本茨——汽车 美国 福特——流水线生产汽车</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>瑞典 诺贝尔——炸药 美国 海厄特——赛璐珞技术、塑料</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>法国 夏尔多内——人造纤维（纺织品）</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">英国 牛顿 近代自然科学奠基人 三大成就：</span>万有引力定律、光学分析、微积分学</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>《自然哲学的数学原理》 物理学成为一门独立的学科</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1859年 英国 达尔文出版《物种起源》</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>19C 法国 巴尔扎克 “人间喜剧”小说集 《欧也妮葛朗台》《高老头》</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>俄国 列夫托尔斯泰 《战争与和平》《安娜卡列尼娜》《复活》 俄国革命的镜子</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>德国 贝多芬 《英雄交响曲》 贝多芬在思想上和艺术上的成熟（写给拿破仑）</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>荷兰 梵高 《夜间的咖啡馆》《向日葵》</p></div><div class="circle-overlay"></div></div></div>',22)])])}const y=i(v,[["render",l]]);export{x as __pageData,y as default};
